INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (565, 165420, 9, 198, '打成这样', '随着阿联酋主裁最后一声哨响，阿根廷人像头中枪的公牛，应声倒下了。洛佩斯跪倒在地，脸面贴着草皮，身体颤抖着。于是，我们知道了什么叫抽噎。而克来斯波，更是毫无顾忌的的红了鼻子，哭得像个孩子。当几个不连续的镜头切换到巴蒂身上时，我们看见战神眼中的泪水，已被那件标式着Argentina的球衣擦去。阿根廷在2002年世界杯上的最后一次表演，就这样结束了。
<br>
<br>   当全世界都在关注贝克汉姆的发型时，贝尔萨说了，即使只用一只脚踢球的贝克汉姆也是可怕的。而98年那位高速带球晃过扎莫特、阿尔梅达、阿亚拉，最后一蹴而就、破门得分的天才少年此次却不在他的关照之列。当阿根廷人将容易受伤的小贝照顾得全场表现平平时，正又是这个少年如匕首般的划过阿根廷人的脖子----一记推射打在门柱内侧惊出阿根廷人一身冷汗。然而，冷汗过后的阿根廷队人依旧头脑发热，波切诺蒂禁区内一脚收不住的围堵成就了欧文一个漂亮的飞摔。如果说86年世界杯是马拉多纳连摸带踢结果了英国人。那么这回却是两英国人连摔带点球终结了阿根廷人。这次成功的突袭，4年前那位于致命部位给阿根廷人一刀的少年，又贡献了80% 的力量。
<br>
<br>   接下来的时间里，我们看到的是中场梦游的贝隆、马戏团出身的奥特加和埃里克松的战术---英式进攻+意大利防守。赛后英国人兴高采烈得足以像小学算术比赛中获胜的孩子，令人可笑的是，战胜了一个阿根廷似乎却已赢得了世界冠军。有位网友说英格兰人太容易满足了，有位网友说这场比赛踢得太功利，也有位网友说阿根廷人输得很勉强。但从英足协聘请埃里克松出任主教练，我们又不得不佩服英格兰人的良苦用心。毕竟，洛佩斯、贝隆、克雷斯波、阿尔梅达、扎莫特都曾是他的手下爱将。
<br>
<br>    当英格兰人1：0小胜阿根廷人后。瑞典人无疑是充满着必胜的激情的。同胞埃里克松毫不吝啬贡献出了致胜的法宝---前场打阿根廷人的身后，最好在对方禁区附近制造几个定位球---因为疯子教练防守的思维是选个纸糊的守门员当正选。后场防守，大可派双塔紧盯巴蒂，再来个意大利式的大铁桶便安全不过了。至于对小毛驴的防守。大可当他触球时上一个机灵的后卫围逼。因为驴毕竟是驴，即便对阵瑞典也不会变成黑马，几次粘球杂耍一番，禁区突破，他总能稳稳的把球准确无误的传到我方队员脚下。就这样，瑞典人成功的拾着英格兰人的牙慧，成功的逼平了阿根廷人。
<br>    想想已出线的几支步入16强的队伍，有对喀麦隆打防守反击的德国队，打法几乎出自同一流派的英格兰、丹麦、瑞典、爱尔兰。3：0领先后又被逼平的塞内加尔。时而天堂神仙漫步，时而地狱油锅煎熬的西班牙，还有只会把捏软柿子---中国队的巴西。
<br>    不由感慨,世界杯打成这样都快跟那微笑着的沈冰娘们一样----俗不可耐了。', '随着阿联酋主裁最后一声哨响，阿根廷人像头中枪的公牛，应声倒下了。洛佩斯跪倒在地，脸面贴着草皮，身体颤抖着。于是，我们知道了什么叫抽噎。而克来斯波，更是毫无顾忌的的红了鼻子，哭得像个孩子。当几个不连续的镜头切换到巴蒂身上时，我们看见战神眼中的泪水，已被那件标式着Argentina的球衣擦去。阿根廷在2002年世界杯上的最后一次表演，就这样结束了。

当全世界都在关注贝克汉姆的发型时，贝尔萨说了，即使只用一只脚踢球的贝克汉姆也是可怕的。而98年那位高速带球晃过扎莫特、阿尔梅达、阿亚拉，最后一蹴而就、破门得分的天才少年此次却不在他的关照之列。当阿根廷人将容易受伤的小贝照顾得全场表现平平时，正又是这个少年如匕首般的划过阿根廷人的脖子----一记推射打在门柱内侧惊出阿根廷人一身冷汗。然而，冷汗过后的阿根廷队人依旧头脑发热，波切诺蒂禁区内一脚收不住的围堵成就了欧文一个漂亮的飞摔。如果说86年世界杯是马拉多纳连摸带踢结果了英国人。那么这回却是两英国人连摔带点球终结了阿根廷人。这次成功的突袭，4年前那位于致命部位给阿根廷人一刀的少年，又贡献了80% 的力量。

接下来的时间里，我们看到的是中场梦游的贝隆、马戏团出身的奥特加和埃里克松的战术---英式进攻+意大利防守。赛后英国人兴高采烈得足以像小学算术比赛中获胜的孩子，令人可笑的是，战胜了一个阿根廷似乎却已赢得了世界冠军。有位网友说英格兰人太容易满足了，有位网友说这场比赛踢得太功利，也有位网友说阿根廷人输得很勉强。但从英足协聘请埃里克松出任主教练，我们又不得不佩服英格兰人的良苦用心。毕竟，洛佩斯、贝隆、克雷斯波、阿尔梅达、扎莫特都曾是他的手下爱将。

当英格兰人1：0小胜阿根廷人后。瑞典人无疑是充满着必胜的激情的。同胞埃里克松毫不吝啬贡献出了致胜的法宝---前场打阿根廷人的身后，最好在对方禁区附近制造几个定位球---因为疯子教练防守的思维是选个纸糊的守门员当正选。后场防守，大可派双塔紧盯巴蒂，再来个意大利式的大铁桶便安全不过了。至于对小毛驴的防守。大可当他触球时上一个机灵的后卫围逼。因为驴毕竟是驴，即便对阵瑞典也不会变成黑马，几次粘球杂耍一番，禁区突破，他总能稳稳的把球准确无误的传到我方队员脚下。就这样，瑞典人成功的拾着英格兰人的牙慧，成功的逼平了阿根廷人。

想想已出线的几支步入16强的队伍，有对喀麦隆打防守反击的德国队，打法几乎出自同一流派的英格兰、丹麦、瑞典、爱尔兰。3：0领先后又被逼平的塞内加尔。时而天堂神仙漫步，时而地狱油锅煎熬的西班牙，还有只会把捏软柿子---中国队的巴西。

不由感慨,世界杯打成这样都快跟那微笑着的沈冰娘们一样----俗不可耐了。', NULL, '2002-06-13 00:18:00', 7, '20020621104938_bbsid_165420_board_9_42c91234ba.html', '20020621104938');
